    private async Task LoadSalesAsync()
    {
        isLoading = true;
        errorMessage = string.Empty;
        sales = new List<IBIZWebApp.Models.SalesOrder>();
        if (CompanyService.SelectedCompany == null)
        {
            errorMessage = "No company selected. Please log in again.";
            isLoading = false;
            return;
        }

        string url;
        int page = 1;
        int pageSize = 10;
        if (string.IsNullOrWhiteSpace(searchTerm))
        {
            // Fetch all data (no search param)
            url = $"{IBIZWebApp.ApiConstants.BaseUrl}/api/Order/search-sales?page={page}&pageSize={pageSize}";
        }
        else
        {
            url = $"{IBIZWebApp.ApiConstants.BaseUrl}/api/Order/search-sales?search={Uri.EscapeDataString(searchTerm)}&page={page}&pageSize={pageSize}";
        }
        var cdkey = CompanyService.SelectedCompany?.LicenceKey ?? string.Empty;
        var companyCode = CompanyService.SelectedCompany?.CompanyCode ?? string.Empty;
        var request = new HttpRequestMessage(HttpMethod.Get, url);
        request.Headers.Add("CdyKey", cdkey);
        request.Headers.Add("CompanyCode", companyCode);
        var response = await Http.SendAsync(request);
        if (response.IsSuccessStatusCode)
        {
            var json = await response.Content.ReadAsStringAsync();
            var pagedResult = System.Text.Json.JsonSerializer.Deserialize<IBIZWebApp.Models.PagedResponse<IBIZWebApp.Models.SalesOrder>>(json, new System.Text.Json.JsonSerializerOptions { PropertyNameCaseInsensitive = true });
            var filtered = pagedResult?.Items ?? new List<IBIZWebApp.Models.SalesOrder>();
            if (!string.IsNullOrEmpty(selectedStatus))
            {
                filtered = filtered.Where(o => o.Status == selectedStatus).ToList();
            }
            sales = filtered;
        }
        else
        {
            errorMessage = "Failed to load sales list.";
        }
        isLoading = false;
    }

    private void EditSale(string? saleId)
    {
        if (string.IsNullOrEmpty(saleId) || saleId == "0")
        {
            Navigation.NavigateTo("/sales");
        }
        else
        {
            Navigation.NavigateTo($"/sales/{saleId}");
        }
    }

    private void ViewSale(string? saleId)
    {
        if (!string.IsNullOrEmpty(saleId))
        {
            Navigation.NavigateTo($"/sales/{saleId}?view=true");
        }
    }

    private void ConfirmDelete(string? saleId)
    {
        saleIdToDelete = saleId;
        showDeleteConfirm = true;
    }

    private void CancelDelete()
    {
        showDeleteConfirm = false;
        saleIdToDelete = null;
    }

    private async void DeleteSaleConfirmed()
    {
        if (string.IsNullOrEmpty(saleIdToDelete))
        {
            showDeleteConfirm = false;
            return;
        }
        try
        {
            var cdkey = CompanyService.SelectedCompany?.LicenceKey ?? string.Empty;
            var companyCode = CompanyService.SelectedCompany?.CompanyCode ?? string.Empty;
            var url = $"{IBIZWebApp.ApiConstants.BaseUrl}/api/Order/{saleIdToDelete}";
            var request = new HttpRequestMessage(HttpMethod.Delete, url);
            request.Headers.Add("CdyKey", cdkey);
            request.Headers.Add("CompanyCode", companyCode);
            var response = await Http.SendAsync(request);
            if (response.IsSuccessStatusCode)
            {
                errorMessage = "Sale deleted successfully.";
                await LoadSalesAsync();
            }
            else
            {
                errorMessage = "Failed to delete sale.";
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Error deleting sale: {ex.Message}";
        }
        showDeleteConfirm = false;
        saleIdToDelete = null;
        StateHasChanged();
    }

